import sys

def main():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:]))

    positions = {}
    for idx, val in enumerate(A):
        if val not in positions:
            positions[val] = []
        positions[val].append(idx + 1)  # 1-based index

    # Sort numbers 1 to N based on the middle occurrence
    result = []
    for i in range(1, N + 1):
        result.append(i)

    result.sort(key=lambda x: positions[x][1])
    print(' '.join(map(str, result)))

if __name__ == "__main__":
    main()
